```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
  url      = "file:./dev.db"
}

model User {
  id        String   @id @default(uuid())
  name      String
  pin       String
  role      String
  active    Boolean  @default(true)
  tipPoints Float?   @default(0)
  shifts    Shift[]
}

model Shift {
  id            String    @id @default(uuid())
  userId        String
  user          User      @relation(fields: [userId], references: [id])
  startTime     DateTime
  endTime       DateTime?
  durationHours Float?
}

model Product {
  id          String       @id @default(uuid())
  name        String
  price       Float
  category    String
  description String?
  image       String?
  active      Boolean      @default(true)
  recipe      RecipeItem[]
  orderItems  OrderItem[]
}

model Ingredient {
  id            String       @id @default(uuid())
  name          String
  unit          String
  costPerUnit   Float
  currentStock  Float
  minStockAlert Float
  recipeItems   RecipeItem[]
}

model RecipeItem {
  id           String     @id @default(uuid())
  productId    String
  product      Product    @relation(fields: [productId], references: [id])
  ingredientId String
  ingredient   Ingredient @relation(fields: [ingredientId], references: [id])
  quantity     Float
}

model Order {
  id        String      @id @default(uuid())
  tableId   Int
  type      String      // dine_in, takeaway, delivery
  status    String
  total     Float
  timestamp DateTime    @default(now())
  waiterId  String?
  driverId  String?
  platform  String?
  items     OrderItem[]
}

model OrderItem {
  id        String  @id @default(uuid())
  orderId   String
  order     Order   @relation(fields: [orderId], references: [id])
  productId String? // Optional because product might be deleted
  product   Product? @relation(fields: [productId], references: [id])
  name      String
  price     Float
  quantity  Int
  notes     String?
}
```

## backend/src/server.ts

```typescript
import express from 'express';
import http from 'http';
import { Server } from 'socket.io';
import cors from 'cors';
import { PrismaClient } from '@prisma/client';

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: "*", 
    methods: ["GET", "POST", "PUT", "DELETE"]
  }
});

const prisma = new PrismaClient();

app.use(cors());
app.use(express.json());

// --- WEBSOCKETS ---
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);
  socket.on('join_room', (room) => socket.join(room));
});

// --- API ROUTES ---

// PRODUCTS (MENU)
app.get('/api/menu', async (req, res) => {
  try {
    const products = await prisma.product.findMany({ 
      include: { recipe: true } 
    });
    res.json(products);
  } catch (e) {
    res.status(500).json({ error: 'Failed to fetch menu' });
  }
});

// ORDERS
app.get('/api/orders', async (req, res) => {
  try {
    const orders = await prisma.order.findMany({
      where: { status: { notIn: ['paid', 'cancelled'] } },
      include: { items: true }
    });
    res.json(orders);
  } catch (e) {
    res.status(500).json({ error: 'Failed to fetch orders' });
  }
});

app.post('/api/orders', async (req, res) => {
  const { tableId, type, items, waiterId, total, platform } = req.body;
  try {
    const order = await prisma.order.create({
      data: {
        tableId, type, status: 'pending', total, waiterId, platform,
        items: {
          create: items.map((i: any) => ({
            productId: i.id, // Assuming i.id is the product ID
            name: i.name,
            price: i.price,
            quantity: i.quantity,
            notes: i.notes
          }))
        }
      },
      include: { items: true }
    });

    // Stock Deduction Logic
    for (const item of items) {
      if (item.id) {
        const product = await prisma.product.findUnique({ 
            where: { id: item.id }, 
            include: { recipe: true } 
        });

        if (product?.recipe) {
          for (const rItem of product.recipe) {
            await prisma.ingredient.update({
              where: { id: rItem.ingredientId },
              data: { currentStock: { decrement: rItem.quantity * item.quantity } }
            });
          }
        }
      }
    }

    io.emit('new_order', order);
    res.json(order);
  } catch (e) {
    console.error(e);
    res.status(500).json({ error: 'Failed to create order' });
  }
});

app.put('/api/orders/:id/status', async (req, res) => {
  const { id } = req.params;
  const { status } = req.body;
  try {
    const order = await prisma.order.update({
        where: { id },
        data: { status },
        include: { items: true }
    });
    io.emit('order_update', order);
    res.json(order);
  } catch (e) {
      res.status(500).json({ error: 'Failed to update order' });
  }
});

// INVENTORY
app.get('/api/inventory', async (req, res) => {
  try {
    const ingredients = await prisma.ingredient.findMany();
    res.json(ingredients);
  } catch(e) {
      res.status(500).json({ error: 'Failed to fetch inventory' });
  }
});

app.post('/api/inventory/nir', async (req, res) => {
    const { items } = req.body; // items: { ingredientId, quantity, price }[]
    try {
        for(const item of items) {
            await prisma.ingredient.update({
                where: { id: item.ingredientId },
                data: { 
                    currentStock: { increment: item.quantity }, 
                    costPerUnit: item.price 
                } 
            });
        }
        res.json({ success: true });
    } catch(e) {
        res.status(500).json({ error: 'NIR failed' });
    }
});

// USERS & SHIFTS
app.get('/api/users', async (req, res) => {
    const users = await prisma.user.findMany();
    res.json(users);
});

app.post('/api/shifts/start', async (req, res) => {
    const { userId } = req.body;
    try {
        const shift = await prisma.shift.create({
            data: { userId, startTime: new Date() }
        });
        res.json(shift);
    } catch(e) {
        res.status(500).json({ error: 'Failed to start shift' });
    }
});

app.post('/api/shifts/end', async (req, res) => {
    const { shiftId } = req.body;
    try {
        const shift = await prisma.shift.update({
            where: { id: shiftId },
            data: { endTime: new Date() }
        });
        res.json(shift);
    } catch(e) {
        res.status(500).json({ error: 'Failed to end shift' });
    }
});

const PORT = 3000;
server.listen(PORT, () => {
  console.log(`Backend running on http://localhost:${PORT}`);
});

