// 2. ORDERS
app.get('/api/orders', async (req, res) => {
  const orders = await prisma.order.findMany({
    where: { status: { notIn: ['paid', 'cancelled'] } },
    include: { items: true }
  });
  res.json(orders);
});
app.post('/api/orders', async (req, res) => {
  const { tableId, type, items, waiterId, total, platform, clientId } = req.body;
  try {
    const order = await prisma.order.create({
      data: {
        tableId, type, status: 'pending', total, waiterId, platform, clientId,
        items: {
          create: items.map((i: any) => ({
            productId: i.id,
            name: i.name,
            price: i.price,
            quantity: i.quantity,
            notes: i.notes,
            station: i.station
          }))
        }
      },
      include: { items: true }
    });

    // Deduct Stock
    for (const item of items) {
        if (item.id) {
            const product = await prisma.product.findUnique({ where: { id: item.id }, include: { recipe: true } });
            if (product?.recipe) {
                for (const rItem of product.recipe) {
                    await prisma.ingredient.update({
                        where: { id: rItem.ingredientId },
                        data: { currentStock: { decrement: rItem.quantity * item.quantity } }
                    });
                }
            }
        }
    }

    io.emit('new_order', order);
    res.json(order);
  } catch(e) { res.status(500).json({error: "Order failed"}); }
});
app.put('/api/orders/:id/status', async (req, res) => {
    const { id } = req.params;
    const { status } = req.body;
    const order = await prisma.order.update({ where: { id }, data: { status }, include: { items: true } });
