                type: 'incoming',
                date: new Date(),
                supplierId,
                totalValue: items.reduce((a:number, b:any) => a + (b.quantity * b.price), 0),
                status: 'posted',
                itemsJSON: JSON.stringify(items)
            }
        });
        for(const item of items) {
            await prisma.ingredient.update({
                where: { id: item.ingredientId },
                data: { currentStock: { increment: item.quantity }, costPerUnit: item.price }
            });
        }
        res.json({ success: true });
    } catch(e) { res.status(500).json({error: "NIR failed"}); }
});
