app.post('/api/orders', async (req, res) => {
  const { tableId, type, items, waiterId, total, platform, clientId, deliveryInfo } = req.body;
  try {
    const order = await prisma.order.create({
      data: {
        tableId, type, status: 'pending', total, waiterId, platform, clientId,
        deliveryInfo: deliveryInfo ? JSON.stringify(deliveryInfo) : null,
        items: {
