                ))}

                {/* VAT Analysis */}
                <div style={{marginTop:'10px', borderTop:'1px dashed black', paddingTop:'5px', fontSize:'10px'}}>
                    <div style={{display:'flex', justifyContent:'space-between', fontWeight:'bold', borderBottom:'1px solid #ccc'}}>
                        <span>Cota</span>
                        <span>Baza</span>
                        <span>TVA</span>
                    </div>
                    {Object.entries(calculateVatBreakdown(receiptToPrint)).map(([rate, vals]) => (
                        <div key={rate} style={{display:'flex', justifyContent:'space-between'}}>
                            <span>{rate}%</span>
                            <span>{vals.base.toFixed(2)}</span>
                            <span>{vals.vat.toFixed(2)}</span>
                        </div>
                    ))}
                </div>

                <div style={{borderTop:'1px dashed black', marginTop:'5px', paddingTop:'5px'}}>
                    <div style={{display:'flex', justifyContent:'space-between', fontWeight:'bold', fontSize:'14px'}}>
                        <span>TOTAL</span>
                        <span>{receiptToPrint.total.toFixed(2)} RON</span>
                    </div>
                    {tipAmount > 0 && (
                        <div style={{display:'flex', justifyContent:'space-between', fontSize:'10px'}}>
                            <span>Bacsis</span>
                            <span>{tipAmount.toFixed(2)} RON</span>
                        </div>
                    )}
                </div>
                <div className="footer">
                    VA MULTUMIM!<br/>
                    Va mai asteptam.
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
```

## components/Operations.tsx

Migrated item status updates and production execution to `ApiService`.

```tsx
import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, Department, ProductCategory, OrderItem, ModifierOption, MenuItem, KitchenStation } from '../types';
import { Clock, CheckCircle, Flame, BellRing, Beer, ChefHat, User, Printer, Layers, List, ClipboardList, Info, X, PauseCircle, Moon, Sun, ShoppingBag, RotateCcw, History, Filter, Volume2, VolumeX, CheckSquare, Square, Scale, ArrowRight, Keyboard, Sigma } from 'lucide-react';
import { ApiService } from '../services/api';

interface OperationsProps {
  orders: Order[];
  onUpdateStatus: (orderId: string, status: OrderStatus) => void;
  notify: (msg: string, type: 'success' | 'error' | 'info') => void;
  menuItems?: MenuItem[];
}

// Helper interface for aggregated items
interface AggregatedItem {
    name: string;
    quantity: number;
    modifiers: ModifierOption[];
    orderIds: string[];
    category: ProductCategory;
}

export const Operations: React.FC<OperationsProps> = ({ orders, onUpdateStatus, notify, menuItems = [] }) => {
  const [view, setView] = useState<Department>(Department.KITCHEN);
  const [mode, setMode] = useState<'orders' | 'items' | 'prep' | 'history' | 'allday'>('orders');
  const [ticketToPrint, setTicketToPrint] = useState<Order | null>(null);
  const [prepList, setPrepList] = useState<{name: string, projected: number, productId?: string}[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [stationFilter, setStationFilter] = useState<KitchenStation | 'All'>('All');

  // Bump Bar State
  const [showBumpBar, setShowBumpBar] = useState(true);

  // Audio State
  const [soundEnabled, setSoundEnabled] = useState(false);
  const [lastOrderCount, setLastOrderCount] = useState(0);

  // Recipe Popup State
  const [viewRecipe, setViewRecipe] = useState<MenuItem | null>(null);

  // Prep Modal State
  const [selectedPrepItem, setSelectedPrepItem] = useState<{name: string, projected: number, productId?: string} | null>(null);
  const [prepQuantity, setPrepQuantity] = useState(10);

  // Filter orders based on view AND station
  const filteredOrders = orders.filter(o => {
    if (o.status === OrderStatus.PAID || o.status === OrderStatus.CANCELLED) return false;

    // Determine if order has items for this department
    let hasDeptItems = false;
    if (view === Department.KITCHEN) {
        hasDeptItems = o.items.some(i => i.category === ProductCategory.FOOD || i.category === ProductCategory.DESSERT) && o.status !== OrderStatus.READY_FOOD;
    } else if (view === Department.BAR) {
        hasDeptItems = o.items.some(i => i.category === ProductCategory.DRINKS || i.category === ProductCategory.ALCOHOL || i.category === ProductCategory.COFFEE) && o.status !== OrderStatus.READY_BAR;
    } else {
        return o.status === OrderStatus.READY_FOOD || o.status === OrderStatus.READY_BAR || o.status === OrderStatus.SERVED;
    }

    if (!hasDeptItems) return false;

    // Filter by Station if applicable
    if (stationFilter !== 'All' && view === Department.KITCHEN) {
        const hasStationItems = o.items.some(item => item.station === stationFilter);
        if (!hasStationItems) return false;
    }

    return true;
  });

  // TTS Effect
  useEffect(() => {
      if (filteredOrders.length > lastOrderCount) {
          if (soundEnabled) {
              const msg = new SpeechSynthesisUtterance(`Comandă nouă, Masa ${filteredOrders[filteredOrders.length - 1].tableId}`);
              msg.lang = 'ro-RO';
              window.speechSynthesis.speak(msg);
          }
      }
      setLastOrderCount(filteredOrders.length);
  }, [filteredOrders.length, soundEnabled]);

  // History Orders (Completed recently)
  const historyOrders = orders.filter(o => {
      if (view === Department.KITCHEN) {
          return o.status === OrderStatus.READY_FOOD && o.items.some(i => i.category === ProductCategory.FOOD || i.category === ProductCategory.DESSERT);
      }
      if (view === Department.BAR) {
          return o.status === OrderStatus.READY_BAR && o.items.some(i => i.category === ProductCategory.DRINKS || i.category === ProductCategory.ALCOHOL);
      }
      return false;
  }).sort((a,b) => b.timestamp - a.timestamp).slice(0, 20);

  // Calculate Prep List on mode change based on Reservations
  useEffect(() => {
      if(mode === 'prep') {
          const fetchPrepData = async () => {
              const reservations = await ApiService.getReservations();
              const totalGuests = reservations
                .filter(r => r.date === new Date().toISOString().split('T')[0])
                .reduce((acc, r) => acc + r.guests, 0);

              const menu = await ApiService.getMenu();

              const findId = (name: string) => menu.find(m => m.name.includes(name))?.id;

              setPrepList([
                  { name: 'Burger Patties (Vita)', projected: Math.ceil(totalGuests * 0.45) + 5, productId: findId('Burger') },
                  { name: 'Portii Paste (Trufe)', projected: Math.ceil(totalGuests * 0.3) + 3, productId: findId('Paste') },
                  { name: 'Tiramisu (Portii)', projected: Math.ceil(totalGuests * 0.25) + 5, productId: findId('Tiramisu') },
                  { name: 'Sos Pizza (Litri)', projected: 5 },
                  { name: 'Legume Garnitura (Kg)', projected: Math.ceil(totalGuests * 0.1) },
              ]);
          };
          fetchPrepData();
      }
  }, [mode]);

  // HOTKEYS 1-9 & Bump Bar Logic
  const handleBump = (index: number) => {
      const targetOrder = filteredOrders[index];
      if(targetOrder) {
          let nextStatus = OrderStatus.PENDING;
          if(view === Department.WAITERS) nextStatus = OrderStatus.SERVED;
          else if(targetOrder.status === OrderStatus.PENDING) nextStatus = OrderStatus.COOKING;
          else if(view === Department.KITCHEN) nextStatus = OrderStatus.READY_FOOD;
          else nextStatus = OrderStatus.READY_BAR;

          onUpdateStatus(targetOrder.id, nextStatus);
      }
  };

  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if (mode !== 'orders') return;

          // Number Keys 1-8
          const key = Number(e.key);
          if(!isNaN(key) && key > 0 && key <= 8) {
              handleBump(key - 1);
          }

          // Space for First Order (Fast Bump)
          if(e.code === 'Space') {
              e.preventDefault();
              handleBump(0);
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [filteredOrders, mode, view, onUpdateStatus]);

  const handleItemClick = async (orderId: string, itemId: string, currentStatus?: string) => {
      if(currentStatus === 'ready' || currentStatus === 'served') return; 
      await ApiService.updateOrderItemStatus(orderId, itemId, 'ready');
      notify("Articol marcat GATA!", 'success');
  };

  const getStatusColor = (status: OrderStatus) => {
    switch(status) {
      case OrderStatus.PENDING: return isDarkMode ? 'bg-amber-900/50 text-amber-300 border-amber-800' : 'bg-amber-100 text-amber-700 border-amber-200';
      case OrderStatus.COOKING: return isDarkMode ? 'bg-orange-900/50 text-orange-300 border-orange-800' : 'bg-orange-100 text-orange-700 border-orange-200';
      case OrderStatus.READY_FOOD: 
      case OrderStatus.READY_BAR: return isDarkMode ? 'bg-emerald-900/50 text-emerald-300 border-emerald-800' : 'bg-emerald-100 text-emerald-700 border-emerald-200';
      default: return isDarkMode ? 'bg-slate-800 text-slate-300 border-slate-700' : 'bg-slate-100';
    }
  };

  const getPlatformBadge = (order: Order) => {
      if(!order.platform || order.platform === 'internal') return null;

      const colors: Record<string, string> = {
          'glovo': 'bg-yellow-400 text-black',
          'tazz': 'bg-red-600 text-white',
          'bolt_food': 'bg-green-500 text-white',
          'uber_eats': 'bg-black text-white'
      };

      return (
          <div className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${colors[order.platform] || 'bg-gray-500 text-white'}`}>
              {order.platform.replace('_', ' ')}
          </div>
      );
  };

  const handlePrintTicket = (order: Order) => {
      setTicketToPrint(order);
      setTimeout(() => {
          window.print();
          setTicketToPrint(null);
          notify(`Bon de comanda trimis la imprimanta ${view}`, 'info');
      }, 500);
  };

  const handleOpenRecipe = (itemName: string) => {
      const item = menuItems.find(i => i.name === itemName);
      if(item) setViewRecipe(item);
  };

  const handleRecall = (orderId: string) => {
      if(confirm("Readuci comanda in lucru?")) {
          onUpdateStatus(orderId, OrderStatus.COOKING);
          notify("Comanda a fost readusa in ecranul activ (Recall).", 'info');
      }
  };

  const handleExecutePrep = async () => {
      if(!selectedPrepItem || !selectedPrepItem.productId) return;

      try {
          await ApiService.processBatchProduction(selectedPrepItem.productId, prepQuantity);
          notify(`Productie finalizata: ${prepQuantity}x ${selectedPrepItem.name}`, 'success');
          setSelectedPrepItem(null);
      } catch (e) {
          notify("Eroare la productie. Verificati reteta.", 'error');
      }
  };

  // Aggregation Logic (Items Mode)
  const aggregatedItems: AggregatedItem[] = [];
  if (mode === 'items') {
      filteredOrders.forEach(order => {
          order.items.forEach(item => {
              const isKitchen = item.category === ProductCategory.FOOD || item.category === ProductCategory.DESSERT;
              const isBar = item.category === ProductCategory.DRINKS || item.category === ProductCategory.ALCOHOL || item.category === ProductCategory.COFFEE;

              if ((view === Department.KITCHEN && isKitchen) || (view === Department.BAR && isBar)) {
                  // Check station
                  if (view === Department.KITCHEN && stationFilter !== 'All' && item.station !== stationFilter) return;

                  const modKey = item.selectedModifiers?.map(m => m.id).sort().join(',') || '';
                  const existing = aggregatedItems.find(agg => agg.name === item.name && agg.modifiers.map(m => m.id).sort().join(',') === modKey);

                  if (existing) {
                      existing.quantity += item.quantity;
                      existing.orderIds.push(order.id);
                  } else {
                      aggregatedItems.push({
                          name: item.name,
                          quantity: item.quantity,
                          modifiers: item.selectedModifiers || [],
                          orderIds: [order.id],
                          category: item.category as any
                      });
                  }
              }
          });
      });
  }

  // ALL DAY View Logic (Simple total count by name)
  const allDayCounts: Record<string, number> = {};
  if (mode === 'allday') {
      filteredOrders.forEach(order => {
          order.items.forEach(item => {
              // Same filtering
              const isKitchen = item.category === ProductCategory.FOOD || item.category === ProductCategory.DESSERT;
              const isBar = item.category === ProductCategory.DRINKS || item.category === ProductCategory.ALCOHOL || item.category === ProductCategory.COFFEE;
              if ((view === Department.KITCHEN && isKitchen) || (view === Department.BAR && isBar)) {
                  if (view === Department.KITCHEN && stationFilter !== 'All' && item.station !== stationFilter) return;
                  if (item.itemStatus === 'ready' || item.itemStatus === 'served') return; // Exclude done items

                  allDayCounts[item.name] = (allDayCounts[item.name] || 0) + item.quantity;
              }
          });
      });
  }

  // Helper to Group Ticket Items by Course
  const groupItemsByCourse = (items: OrderItem[]) => {
      const groups: Record<string, {item: OrderItem, originalIdx: number}[]> = {
          'course_1': [], 'course_2': [], 'course_3': [], 'other': []
      };

      items.forEach((item, idx) => {
          // Department Check
          if (view === Department.KITCHEN) {
              if (item.category !== ProductCategory.FOOD && item.category !== ProductCategory.DESSERT) return;
          } else if (view === Department.BAR) {
              if (item.category !== ProductCategory.DRINKS && item.category !== ProductCategory.ALCOHOL && item.category !== ProductCategory.COFFEE) return;
          }

          const c = item.course || 'other';
          if(groups[c]) groups[c].push({item, originalIdx: idx});
          else groups['other'].push({item, originalIdx: idx});
      });
      return groups;
  };

  const courseLabels = {
      'course_1': 'Aperitiv / Fel 1',
      'course_2': 'Fel Principal',
      'course_3': 'Desert',
      'other': 'Diverse'
  };

  return (
    <div className={`h-full flex flex-col relative transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-200' : 'bg-slate-50 text-slate-900'}`}>
      {/* Top Bar Switcher */}
      <div className={`border-b px-6 py-4 flex items-center justify-between no-print ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200'}`}>
         <div className="flex gap-4 items-center">
             <div className={`flex gap-2 p-1 rounded-lg ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                 {[
                     { id: Department.KITCHEN, icon: ChefHat, label: 'KDS Bucatarie' },
                     { id: Department.BAR, icon: Beer, label: 'KDS Bar' },
                     { id: Department.WAITERS, icon: User, label: 'Livrare Ospatar' },
                 ].map(dept => (
                     <button
                        key={dept.id}
                        onClick={() => { setView(dept.id); setMode('orders'); }}
                        className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-bold transition-all ${
                            view === dept.id 
                            ? (isDarkMode ? 'bg-slate-700 text-white shadow-sm' : 'bg-white shadow-sm text-slate-800') 
                            : (isDarkMode ? 'text-slate-400 hover:text-slate-200' : 'text-slate-500 hover:text-slate-700')
                        }`}
                     >
                         <dept.icon size={16}/> {dept.label}
                     </button>
                 ))}
             </div>

             {(view === Department.KITCHEN || view === Department.BAR) && (
                 <div className={`flex gap-2 p-1 rounded-lg ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                     <button onClick={() => setMode('orders')} className={`px-3 py-2 rounded-md text-sm font-bold flex items-center gap-2 ${mode === 'orders' ? (isDarkMode ? 'bg-slate-700 text-white' : 'bg-white shadow-sm text-slate-800') : (isDarkMode ? 'text-slate-400' : 'text-slate-500')}`}>
                        <List size={16}/> Comenzi
                     </button>
                     <button onClick={() => setMode('items')} className={`px-3 py-2 rounded-md text-sm font-bold flex items-center gap-2 ${mode === 'items' ? (isDarkMode ? 'bg-slate-700 text-white' : 'bg-white shadow-sm text-slate-800') : (isDarkMode ? 'text-slate-400' : 'text-slate-500')}`}>
                        <Layers size={16}/> Produse
                     </button>
                     <button onClick={() => setMode('allday')} className={`px-3 py-2 rounded-md text-sm font-bold flex items-center gap-2 ${mode === 'allday' ? (isDarkMode ? 'bg-slate-700 text-white' : 'bg-white shadow-sm text-slate-800') : (isDarkMode ? 'text-slate-400' : 'text-slate-500')}`}>
                        <Sigma size={16}/> All Day
                     </button>
                     {view === Department.KITCHEN && (
                         <button onClick={() => setMode('prep')} className={`px-3 py-2 rounded-md text-sm font-bold flex items-center gap-2 ${mode === 'prep' ? (isDarkMode ? 'bg-slate-700 text-white' : 'bg-white shadow-sm text-slate-800') : (isDarkMode ? 'text-slate-400' : 'text-slate-500')}`}>
                            <ClipboardList size={16}/> Prep
                         </button>
                     )}
                     <button onClick={() => setMode('history')} className={`px-3 py-2 rounded-md text-sm font-bold flex items-center gap-2 ${mode === 'history' ? (isDarkMode ? 'bg-slate-700 text-white' : 'bg-white shadow-sm text-slate-800') : (isDarkMode ? 'text-slate-400' : 'text-slate-500')}`}>
                        <History size={16}/> Istoric
                     </button>
                 </div>
             )}

             {view === Department.KITCHEN && (mode === 'orders' || mode === 'allday') && (
                 <div className={`flex items-center gap-2 ml-4 px-3 py-1 rounded-lg border ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-200'}`}>
                     <Filter size={14} className="text-slate-400"/>
                     <select 
                        className={`text-sm font-bold bg-transparent outline-none ${isDarkMode ? 'text-white' : 'text-slate-700'}`}
                        value={stationFilter}
                        onChange={(e) => setStationFilter(e.target.value as any)}
                     >
                         <option value="All">Toate Statiile</option>
                         <option value="Grill">Grill</option>
                         <option value="Pizza">Pizza</option>
                         <option value="Pasta">Pasta</option>
                         <option value="Salad">Salate</option>
                         <option value="Fryer">Friteuza</option>
                         <option value="Dessert">Dessert</option>
                     </select>
                 </div>
             )}
         </div>

         <div className="flex items-center gap-4">
             <button onClick={() => setShowBumpBar(!showBumpBar)} className={`p-2 rounded-full ${showBumpBar ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-400'}`} title="Bump Bar Virtual">
                 <Keyboard size={20}/>
             </button>
             <button onClick={() => setSoundEnabled(!soundEnabled)} className={`p-2 rounded-full ${soundEnabled ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`} title="Alerta Sonora (TTS)">
                 {soundEnabled ? <Volume2 size={20}/> : <VolumeX size={20}/>}
             </button>
             <div className={`text-sm font-medium ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>
                 {filteredOrders.length} Comenzi Active
             </div>
             <button onClick={() => setIsDarkMode(!isDarkMode)} className={`p-2 rounded-full ${isDarkMode ? 'bg-slate-800 text-yellow-400' : 'bg-slate-100 text-slate-600'}`}>
                 {isDarkMode ? <Sun size={20}/> : <Moon size={20}/>}
             </button>
         </div>
      </div>

      {/* Grid */}
      <div className={`p-6 overflow-y-auto no-print ${showBumpBar ? 'mb-24' : ''}`}>
        {mode === 'orders' ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredOrders.length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-64 text-slate-400">
                    <CheckCircle size={64} className="mb-4 opacity-20"/>
                    <p className="text-lg">Nicio comanda in asteptare.</p>
                </div>
                )}

                {filteredOrders.map((order, idx) => {
                    const groupedItems = groupItemsByCourse(order.items);
                    const hasItems = Object.values(groupedItems).some(arr => arr.length > 0);

                    if(!hasItems) return null;

                    // Calculate Order Progress based on itemStatus
                    let totalItems = 0;
                    let completedItems = 0;
                    Object.values(groupedItems).forEach(group => {
                        group.forEach(w => {
                            // Only count items relevant to this department
                            totalItems++;
                            if (w.item.itemStatus === 'ready' || w.item.itemStatus === 'served') completedItems++;
                        });
                    });
                    const progress = totalItems > 0 ? (completedItems / totalItems) * 100 : 0;

                    return (
                    <div key={order.id} className={`rounded-xl shadow-sm border overflow-hidden flex flex-col animate-in fade-in zoom-in duration-300 relative ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-200'}`}>
                        {/* Hotkey Badge */}
                        <div className="absolute top-2 right-12 bg-slate-900 text-white w-6 h-6 rounded-md flex items-center justify-center text-xs font-bold opacity-30">
                            {idx + 1}
                        </div>

                        <div className={`p-4 border-b flex justify-between items-center ${getStatusColor(order.status)}`}>
                        <div>
                            {order.tableId > 0 ? (
                                <span className="font-bold text-lg">Masa {order.tableId}</span>
                            ) : (
                                <div className="flex items-center gap-2">
                                    <span className="font-bold text-lg">Delivery</span>
                                    {getPlatformBadge(order)}
                                </div>
                            )}
                            <span className="block text-xs opacity-70">#{order.id.slice(-4)}</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <button onClick={() => handlePrintTicket(order)} className="p-1.5 hover:bg-white/50 rounded-lg opacity-70 hover:opacity-100" title="Printeaza Bon">
                                <Printer size={16} />
                            </button>
                            <div className="flex items-center gap-1 text-sm font-medium">
                                <Clock size={16} />
                                <span>{Math.floor((Date.now() - new Date(order.timestamp).getTime()) / 60000)} min</span>
                            </div>
                        </div>
                        </div>

                        {/* Progress Bar */}
                        <div className="h-1 w-full bg-slate-200">
                            <div className="h-full bg-emerald-500 transition-all duration-500" style={{width: `${progress}%`}}></div>
                        </div>

                        <div className="p-4 flex-1 overflow-y-auto">
                            {['course_1', 'course_2', 'course_3', 'other'].map(course => {
                                const items = groupedItems[course as keyof typeof groupedItems];
                                if (items.length === 0) return null;

                                // Check Course Status
                                const status = order.courseStatus?.[course] || 'hold';
                                const isFired = status === 'fire' || status === 'served';

                                return (
                                    <div key={course} className={`mb-4 last:mb-0 transition-opacity duration-300 ${!isFired ? 'opacity-40 grayscale -mx-4 px-4 py-2 border-y border-dashed border-slate-700 bg-black/10' : ''}`}>
                                        <div className={`text-[10px] font-bold uppercase mb-1 border-b border-dashed pb-1 flex justify-between items-center ${isDarkMode ? 'text-slate-500 border-slate-700' : 'text-slate-400 border-slate-200'}`}>
                                            <span>{courseLabels[course as keyof typeof courseLabels]}</span>
                                            {!isFired && <span className={`px-2 rounded text-[9px] flex items-center gap-1 ${isDarkMode ? 'bg-slate-700 text-slate-300' : 'bg-slate-200 text-slate-600'}`}><PauseCircle size={10}/> HOLD</span>}
                                        </div>
                                        <ul className="space-y-2">
                                            {items.map((wrapper, i) => {
                                                const { item, originalIdx } = wrapper;
                                                // Station Filter Visual Logic
                                                const isMyStation = stationFilter === 'All' || item.station === stationFilter;
                                                const isItemDone = item.itemStatus === 'ready' || item.itemStatus === 'served';

                                                return (
                                                    <li 
                                                        key={i} 
                                                        className={`flex justify-between items-start group ${!isMyStation ? 'opacity-30' : ''}`}
                                                    >
                                                        <div className="flex gap-3 items-center">
                                                            <button 
                                                                onClick={() => isMyStation && handleItemClick(order.id, item.id, item.itemStatus)}
                                                                disabled={!isMyStation || isItemDone}
                                                                className={`p-1 rounded hover:bg-slate-100 transition-colors ${isItemDone ? 'text-emerald-500' : 'text-slate-300'}`}
                                                            >
                                                                {isItemDone ? <CheckSquare size={18} /> : <Square size={18} />}
                                                            </button>
                                                            <div>
                                                                <div className="flex gap-2">
