                  >
                      Confirma Productie
                  </button>
              </div>
          </div>
      )}

      {/* Hidden Thermal Ticket Template */}
      {ticketToPrint && (
        <div className="print-container">
            <div className="thermal-receipt">
                <h1>{view === Department.BAR ? 'BAR TICKET' : 'KITCHEN TICKET'}</h1>
                {ticketToPrint.platform && ticketToPrint.platform !== 'internal' && (
                    <div style={{textAlign:'center', fontWeight:'bold', fontSize:'14px', marginBottom:'5px', textTransform:'uppercase'}}>
