                <h2>Table {ticketToPrint.tableId > 0 ? ticketToPrint.tableId : 'DELIVERY'}</h2>
                <div style={{display:'flex', justifyContent:'space-between', marginBottom:'10px', fontSize:'10px'}}>
                   <span>ID: {ticketToPrint.id.slice(-4)}</span>
                   <span>{new Date(ticketToPrint.timestamp).toLocaleTimeString()}</span>
                </div>
                <div style={{borderBottom:'1px dashed black', marginBottom:'5px'}}></div>
                {ticketToPrint.items
                    .filter(item => {
                         if (view === Department.KITCHEN) return item.category === ProductCategory.FOOD || item.category === ProductCategory.DESSERT;
                         if (view === Department.BAR) return item.category === ProductCategory.DRINKS || item.category === ProductCategory.ALCOHOL || item.category === ProductCategory.COFFEE;
                         return true;
                    })
                    .map((item, idx) => (
                    <div key={idx} style={{marginBottom:'8px'}}>
                        <div style={{fontSize:'14px', fontWeight:'bold'}}>
                            {item.quantity} x {item.name}
                        </div>
                        {item.selectedModifiers && item.selectedModifiers.map(m => (
                            <div key={m.id} className="modifier">
                                + {m.name}
