                {ticketToPrint.note && (
                    <div style={{marginTop:'10px', fontWeight:'bold', border:'1px solid black', padding:'5px'}}>
                        NOTE: {ticketToPrint.note}
                    </div>
                )}
                <div className="footer">
                    HorecaAI Flow System
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
