```tsx
import React, { useState, useEffect } from 'react';
import { MenuItem, Ingredient, RecipeItem } from '../types';
import { ApiService } from '../services/api';
import { calculateCOGS, calculateMacros } from '../utils/calculations';
import { Scale, Calculator, FileText, Plus, X, MonitorPlay, Minimize, ListChecks, Printer, Sparkles } from 'lucide-react';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell } from 'recharts';
import { getAIPriceSuggestion } from '../services/geminiService';

interface RecipesProps {
  menuItems: MenuItem[];
  onUpdateRecipe: (itemId: string, recipe: RecipeItem[]) => void;
}

export const Recipes: React.FC<RecipesProps> = ({ menuItems, onUpdateRecipe }) => {
  const [selectedProduct, setSelectedProduct] = useState<MenuItem | null>(null);
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [currentRecipe, setCurrentRecipe] = useState<RecipeItem[]>([]);
  const [currentInstructions, setCurrentInstructions] = useState<string[]>([]);
  const [activeTab, setActiveTab] = useState<'ingredients' | 'instructions'>('ingredients');
  const [isCookMode, setIsCookMode] = useState(false);
  const [completedSteps, setCompletedSteps] = useState<number[]>([]);
  const [batchSize, setBatchSize] = useState(1);
  const [detectedAllergens, setDetectedAllergens] = useState<string[]>([]);
  const [showPriceModal, setShowPriceModal] = useState(false);
  const [aiPriceData, setAiPriceData] = useState<any>(null);
  const [isPricing, setIsPricing] = useState(false);

  useEffect(() => {
    ApiService.getInventory().then(setIngredients);
  }, []);

  useEffect(() => {
      if(currentRecipe.length > 0) {
          const allergens = new Set<string>();
          currentRecipe.forEach(rItem => {
              const ing = ingredients.find(i => i.id === rItem.ingredientId);
              if(ing && ing.allergens) {
                  ing.allergens.forEach(a => allergens.add(a));
              }
          });
          setDetectedAllergens(Array.from(allergens));
      } else {
          setDetectedAllergens([]);
      }
  }, [currentRecipe, ingredients]);

  const handleSelectProduct = (item: MenuItem) => {
    setSelectedProduct(item);
    setCurrentRecipe(item.recipe || []);
    setCurrentInstructions(item.instructions || []);
    setBatchSize(1);
    setAiPriceData(null);
    setCompletedSteps([]);
    setActiveTab('ingredients');
  };

  const handleAddIngredient = (ingId: string) => {
    if (!currentRecipe.find(r => r.ingredientId === ingId)) {
        setCurrentRecipe([...currentRecipe, { ingredientId: ingId, quantity: 1, lossPercentage: 0 }]);
    }
  };

  const handleRemoveIngredient = (ingId: string) => {
      setCurrentRecipe(currentRecipe.filter(r => r.ingredientId !== ingId));
  };

  const handleUpdateQuantity = (ingId: string, qty: number) => {
      setCurrentRecipe(currentRecipe.map(r => r.ingredientId === ingId ? { ...r, quantity: qty } : r));
  };

  const addInstruction = () => setCurrentInstructions([...currentInstructions, ""]);
  const updateInstruction = (idx: number, text: string) => {
      const newInst = [...currentInstructions];
      newInst[idx] = text;
      setCurrentInstructions(newInst);
  };
  const removeInstruction = (idx: number) => {
      setCurrentInstructions(currentInstructions.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
      if(selectedProduct) {
          const updatedItem = { 
              ...selectedProduct, 
              recipe: currentRecipe, 
              instructions: currentInstructions,
              allergens: detectedAllergens.length > 0 ? detectedAllergens : selectedProduct.allergens
          };
          await ApiService.saveMenuItem(updatedItem);
          onUpdateRecipe(updatedItem.id, currentRecipe);
          alert('Fisa tehnica si instructiunile au fost salvate!');
      }
  };

  const handleAIPrice = async () => {
      if(!selectedProduct) return;
      setIsPricing(true);
      const totalCost = calculateCOGS(currentRecipe, ingredients);
      const data = await getAIPriceSuggestion(selectedProduct.name, totalCost, selectedProduct.category);
      setAiPriceData(data);
      setIsPricing(false);
      setShowPriceModal(true);
  };

  const totalCost = calculateCOGS(currentRecipe, ingredients);
  const foodCostPercent = selectedProduct ? ((totalCost / selectedProduct.price) * 100).toFixed(1) : 0;
  const macros = calculateMacros(currentRecipe, ingredients);

