          const [m, r, s, u] = await Promise.all([
              ApiService.getMenu(),
              ApiService.saveQuizResult({} as any).then(() => ApiService.getUsers().then(() => [])), // Mock call to fetch results is missing in API definition, reusing user fetch for now or skipping
              ApiService.getSkills(),
              ApiService.getUsers()
          ]);
          setMenu(m);
          setSkills(s);
          setAllUsers(u);
          // Mock user
          setUser(u[1] || u[0]);
