import express from 'express';
import http from 'http';
import { Server } from 'socket.io';
import cors from 'cors';
import { PrismaClient } from '@prisma/client';

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: "*", 
    methods: ["GET", "POST", "PUT", "DELETE"]
  }
});

const prisma = new PrismaClient();

app.use(cors());
app.use(express.json());

// --- WEBSOCKETS ---
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);
  socket.on('join_room', (room) => socket.join(room));
  socket.on('send_message', (msg) => io.emit('new_message', msg));
});

// --- API ROUTES ---

// SETTINGS & TABLES
app.get('/api/settings', async (req, res) => {
    let settings = await prisma.systemSettings.findUnique({ where: { id: 'default' } });
    if (!settings) {
        settings = await prisma.systemSettings.create({
            data: { id: 'default', data: JSON.stringify({ restaurantName: 'New Restaurant' }) }
        });
    }
    res.json(JSON.parse(settings.data));
});

app.post('/api/settings', async (req, res) => {
    const settings = await prisma.systemSettings.upsert({
        where: { id: 'default' },
        update: { data: JSON.stringify(req.body) },
        create: { id: 'default', data: JSON.stringify(req.body) }
    });
    res.json(JSON.parse(settings.data));
});

app.get('/api/tables', async (req, res) => {
    const tables = await prisma.table.findMany();
    res.json(tables);
});

app.post('/api/tables', async (req, res) => {
    const tables = req.body;
    await prisma.table.deleteMany({});
    for (const t of tables) {
        await prisma.table.create({ data: t });
    }
    res.json({ success: true });
