                <h2 className="text-2xl font-bold text-slate-800">Facturare & Documente</h2>
                <p className="text-slate-500 text-sm">Emite facturi fiscale, proforme si gestioneaza documentele.</p>
            </div>
            <div className="flex gap-2">
                <button onClick={refresh} className="p-2 border rounded-lg bg-white hover:bg-slate-50"><RefreshCw size={18}/></button>
                <button onClick={() => setIsModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-slate-800 shadow-lg shadow-slate-900/20">
                    <Plus size={18}/> Factura Noua
                </button>
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
