                <div className="text-3xl font-bold text-slate-800 mt-2">
                    {invoices.filter(i => i.type === 'outgoing').reduce((a,b) => a + b.totalValue, 0).toFixed(2)} RON
                </div>
            </div>
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
                <div className="text-xs font-bold text-slate-500 uppercase">Intrari (Cheltuieli)</div>
                <div className="text-3xl font-bold text-orange-600 mt-2">
                    {invoices.filter(i => i.type === 'incoming').reduce((a,b) => a + b.totalValue, 0).toFixed(2)} RON
                </div>
            </div>
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
                <div className="text-xs font-bold text-slate-500 uppercase">TVA De Plata (Estimat)</div>
                <div className="text-3xl font-bold text-blue-600 mt-2">
                    {(invoices.filter(i => i.type === 'outgoing').reduce((a,b) => a + b.totalValue, 0) * 0.19).toFixed(2)} RON
                </div>
            </div>
        </div>

        <div className="flex-1 ag-theme-quartz shadow-sm rounded-xl overflow-hidden border border-slate-200 bg-white">
            <AgGridReact rowData={invoices} columnDefs={defs} />
        </div>

        {/* New Invoice Modal */}
        {isModalOpen && (
            <div className="fixed inset-0 bg-slate-900/50 flex items-center justify-center z-50 backdrop-blur-sm">
                <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl p-8 max-h-[90vh] overflow-y-auto">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-bold">Emitere Factura Fiscala</h3>
                        <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 font-bold">Inchide</button>
                    </div>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Client</label>
                                <input 
                                    className="w-full border rounded-lg p-2" 
                                    placeholder="Nume Client SRL"
                                    value={formData.clientName}
                                    onChange={e => setFormData({...formData, clientName: e.target.value})}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">CUI</label>
                                <input 
                                    className="w-full border rounded-lg p-2" 
                                    placeholder="RO..." 
                                    value={formData.clientCUI}
                                    onChange={e => setFormData({...formData, clientCUI: e.target.value})}
                                />
                            </div>
                        </div>

                        <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                            <h4 className="font-bold text-sm mb-3 text-slate-700">Articole</h4>
                            {formData.items.map((item, idx) => (
                                <div key={idx} className="flex gap-2 mb-2">
                                    <input 
