                        <button onClick={() => setIsListening(true)} className={`p-2 rounded-full ${isListening ? 'bg-red-500 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`} title="Comanda Vocala"><Mic size={18}/></button>
