            <p className="text-slate-500 text-sm">Real-time business intelligence</p>
          </div>
          <div className="text-right">
              <div className="text-sm font-bold text-slate-500">Live Status</div>
              <div className="flex items-center gap-2 text-emerald-600 font-bold text-sm">
                  <span className="relative flex h-3 w-3">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-emerald-500"></span>
                  </span>
                  Operational
              </div>
          </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard 
            title="Venituri Totale" 
            value={`${totalRevenue} RON`} 
            subtext="+12% vs Saptamana Trecuta" 
            icon={DollarSign} 
            bgClass="bg-emerald-500" 
            iconClass="text-emerald-600"
            textClass="text-emerald-500"
        />
        <StatCard 
            title="Food Cost" 
            value="32%" 
            subtext="Target: <30%" 
            icon={Utensils} 
            bgClass="bg-orange-500"
            iconClass="text-orange-600"
            textClass="text-orange-500"
        />
        <StatCard 
            title="Satisfactie Clienti" 
            value={rating > 0 ? rating.toFixed(1) : '-'} 
            subtext="Rating Mediu" 
            icon={Smile} 
            bgClass="bg-blue-500"
            iconClass="text-blue-600"
            textClass="text-blue-500"
        />
        <StatCard 
            title="Oaspeti" 
            value={paidOrders.length * 2 + 12} 
            subtext="Grad Ocupare: 78%" 
            icon={Users} 
            bgClass="bg-violet-500"
            iconClass="text-violet-600"
            textClass="text-emerald-500"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col h-80">
              <h3 className="font-bold text-slate-700 mb-4">Trend Vanzari (Ultimele 7 Zile)</h3>
              <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={weeklyData}>
                      <defs>
                          <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                              <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
                              <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
                          </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" axisLine={false} tickLine={false}/>
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#8884d8" fillOpacity={1} fill="url(#colorSales)" />
                  </AreaChart>
              </ResponsiveContainer>
          </div>

          <div className="flex flex-col gap-6 h-80">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex-1 relative overflow-hidden">
                  <div className="flex justify-between items-center mb-4 relative z-10">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2"><Target size={20} className="text-indigo-600"/> Target Zilnic</h3>
                      <span className="text-xs font-bold bg-indigo-50 text-indigo-700 px-2 py-1 rounded">{targetProgress.toFixed(0)}%</span>
                  </div>
                  <div className="relative pt-2 z-10">
                      <div className="text-3xl font-bold text-slate-800">{totalRevenue.toFixed(0)} <span className="text-lg text-slate-400">/ {dailyTarget}</span></div>
                      <div className="h-4 w-full bg-slate-100 rounded-full mt-4 overflow-hidden">
