                      )}
                  </div>
                  {lowStockItems.length > 4 && <div className="text-center text-xs text-red-500 font-bold mt-2 relative z-10">... si inca {lowStockItems.length - 4}</div>}
              </div>
          </div>
      </div>
    </div>
  );
};
