app.post('/api/orders', async (req, res) => {
  const { tableId, type, items, waiterId, total, platform, clientId, deliveryInfo } = req.body;
  try {
    const order = await prisma.order.create({
      data: {
        tableId, type, status: 'pending', total, waiterId, platform, clientId,
        deliveryInfo: deliveryInfo ? JSON.stringify(deliveryInfo) : null,
        items: {
          create: items.map((i: any) => ({
            productId: i.id,
            name: i.name,
            price: i.price,
            quantity: i.quantity,
            notes: i.notes,
            station: i.station,
            category: i.category,
            course: i.course,
            seatIdx: i.seatIdx,
            selectedModifiers: JSON.stringify(i.selectedModifiers)
          }))
        }
      },
      include: { items: true }
    });

    // Deduct Stock
    for (const item of items) {
        if (item.id) {
            const product = await prisma.product.findUnique({ where: { id: item.id }, include: { recipe: true } });
            if (product?.recipe) {
                for (const rItem of product.recipe) {
                    await prisma.ingredient.update({
                        where: { id: rItem.ingredientId },
                        data: { currentStock: { decrement: rItem.quantity * item.quantity } }
                    });
                }
            }
        }
    }

    io.emit('new_order', order);
    res.json(order);
  } catch(e) { console.error(e); res.status(500).json({error: "Order failed"}); }
});

