export const Scoreboard: React.FC = () => {
  const [activeOrders, setActiveOrders] = useState<Order[]>([]);
  const [stats, setStats] = useState({
      avgTime: 0,
      totalDone: 0,
      ordersPerHour: 0
  });

  useEffect(() => {
      const fetchData = async () => {
          const active = await ApiService.getOrders();
          const archived = await ApiService.getArchivedOrders();
          const allOrders = [...active, ...archived];
          const today = new Date().toDateString();

          const todaysOrders = allOrders.filter(o => new Date(o.timestamp).toDateString() === today);
          const cooking = todaysOrders.filter(o => o.status === OrderStatus.COOKING || o.status === OrderStatus.PENDING);
          const done = todaysOrders.filter(o => o.status === OrderStatus.READY_FOOD || o.status === OrderStatus.READY_BAR || o.status === OrderStatus.SERVED || o.status === OrderStatus.PAID);

          const completedTimes = done.map(o => Math.floor(Math.random() * 20) + 5); // Mock duration as timestamp only in basic model
          const avg = completedTimes.length > 0 ? completedTimes.reduce((a,b) => a+b, 0) / completedTimes.length : 0;

          const hoursOpen = (new Date().getHours() - 9) || 1; 
          const pace = Math.round(todaysOrders.length / hoursOpen);

          setActiveOrders(cooking.sort((a,b) => a.timestamp - b.timestamp));
          setStats({
              avgTime: Math.round(avg),
              totalDone: done.length,
              ordersPerHour: pace
          });
      };

      fetchData();
      const interval = setInterval(fetchData, 5000);
      return () => clearInterval(interval);
