                  <div className="w-48 h-48 bg-orange-100 rounded-full flex items-center justify-center text-orange-600">
                      <ShoppingBag size={80}/>
                  </div>
                  <span className="text-5xl font-black text-slate-800">TAKEAWAY</span>
