app.post('/api/orders/:id/void', async (req, res) => {
    const { id } = req.params;
    const { itemIdx, reason, returnStock, user } = req.body;

    const order = await prisma.order.findUnique({ where: { id }, include: { items: true } });
    if(!order || !order.items[itemIdx]) return res.status(404).json({error: "Item not found"});

    const item = order.items[itemIdx];

    // Return Stock
    if (returnStock && item.productId) {
        const product = await prisma.product.findUnique({ where: { id: item.productId }, include: { recipe: true } });
        if (product?.recipe) {
            for (const rItem of product.recipe) {
                await prisma.ingredient.update({
                    where: { id: rItem.ingredientId },
                    data: { currentStock: { increment: rItem.quantity * item.quantity } }
                });
            }
        }
    }

    // Delete Item
    await prisma.orderItem.delete({ where: { id: item.id } });

    // Recalculate Total
    const updatedOrder = await prisma.order.findUnique({ where: { id }, include: { items: true } });
    if(updatedOrder) {
        const newTotal = updatedOrder.items.reduce((acc, i) => acc + (i.price * i.quantity), 0);
        await prisma.order.update({ where: { id }, data: { total: newTotal } });

        await prisma.auditLog.create({
            data: {
                action: 'VOID_ITEM',
                user: user || 'Unknown',
                details: `Voided ${item.name} from Order ${id}. Reason: ${reason}`
            }
        });

        const finalOrder = {
            ...updatedOrder, 
            total: newTotal,
            deliveryInfo: updatedOrder.deliveryInfo ? JSON.parse(updatedOrder.deliveryInfo) : null,
            splitBill: updatedOrder.splitBill ? JSON.parse(updatedOrder.splitBill) : null,
            courseStatus: updatedOrder.courseStatus ? JSON.parse(updatedOrder.courseStatus) : null,
            items: updatedOrder.items.map(i => ({
                ...i,
                selectedModifiers: i.selectedModifiers ? JSON.parse(i.selectedModifiers) : []
            }))
        };

        io.emit('order_update', finalOrder);
        res.json({ success: true });
    } else {
        res.status(500).json({ error: "Order lost" });
    }
});

app.post('/api/orders/transfer', async (req, res) => {
    const { fromTableId, toTableId, user } = req.body;

    const sourceOrder = await prisma.order.findFirst({ where: { tableId: fromTableId, status: { notIn: ['paid', 'cancelled'] } }, include: { items: true } });
    if(!sourceOrder) return res.status(404).json({error: "Source order not found"});

    const targetOrder = await prisma.order.findFirst({ where: { tableId: toTableId, status: { notIn: ['paid', 'cancelled'] } } });

    if(targetOrder) {
        // Merge
        await prisma.orderItem.updateMany({
            where: { orderId: sourceOrder.id },
            data: { orderId: targetOrder.id }
        });
        await prisma.order.update({
            where: { id: targetOrder.id },
            data: { total: { increment: sourceOrder.total } }
        });
        await prisma.order.delete({ where: { id: sourceOrder.id } });
        await prisma.auditLog.create({ data: { action: 'MERGE_TABLE', user, details: `Merged ${fromTableId} to ${toTableId}` } });
    } else {
        // Transfer
        await prisma.order.update({
            where: { id: sourceOrder.id },
            data: { tableId: toTableId }
        });
        await prisma.auditLog.create({ data: { action: 'TRANSFER_TABLE', user, details: `Transferred ${fromTableId} to ${toTableId}` } });
    }

    await prisma.table.update({ where: { id: fromTableId }, data: { occupied: false } });
    await prisma.table.update({ where: { id: toTableId }, data: { occupied: true } });

    res.json({ success: true });
});

