            await prisma.product.create({ data: { name: 'Papanasi', price: 25, category: 'Desert', station: 'Dessert', active: true } });
        }

        // 3. Create Default Tables
        const tableCount = await prisma.table.count();
        if (tableCount === 0) {
            for(let i=1; i<=10; i++) {
                await prisma.table.create({ data: { id: i, zone: 'Interior', seats: 4, occupied: false, reserved: false, shape: 'square' } });
