      setIsChecking(true);
      setTimeout(() => {
          const hour = parseInt(formData.time.split(':')[0]);
          const isOk = hour >= 12 && hour <= 22; 
          setIsAvailable(isOk);
          setIsChecking(false);
      }, 1000);
