                            <div><strong>Persoane:</strong> {formData.pax}</div>
                        </div>
                        <button onClick={() => { setStep(1); setIsAvailable(null); }} className="block w-full py-3 text-blue-600 font-bold hover:bg-blue-50 rounded-xl">
                            Rezerva din nou
                        </button>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};
