export const Dashboard: React.FC<DashboardProps> = ({ orders }) => {
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [rating, setRating] = useState(0);
  const [leaderboard, setLeaderboard] = useState<{name: string, sales: number, rank: number}[]>([]);
  const [dailyTarget, setDailyTarget] = useState(5000);

  useEffect(() => {
      const fetchData = async () => {
          const [ing, feedbacks, settings, users, archived] = await Promise.all([
              ApiService.getInventory(),
              ApiService.getFeedback(),
              ApiService.getSettings(),
              ApiService.getUsers(),
              ApiService.getArchivedOrders()
          ]);

          setIngredients(ing);

          if(feedbacks.length > 0) {
              const avg = feedbacks.reduce((acc, f) => acc + f.rating, 0) / feedbacks.length;
              setRating(avg);
          }

          if(settings.dailySalesTarget) setDailyTarget(settings.dailySalesTarget);

          // Calculate Leaderboard
          const allOrders = [...orders, ...archived];
          const stats: Record<string, number> = {};

          allOrders.filter(o => o.status === OrderStatus.PAID).forEach(o => {
              const wId = o.waiterId || 'unknown';
              if(!stats[wId]) stats[wId] = 0;
              stats[wId] += o.total;
          });

          const sorted = Object.entries(stats)
            .map(([id, total]) => {
                const user = users.find(u => u.id === id);
                return { name: user ? user.name : 'Unknown', sales: total };
            })
            .sort((a,b) => b.sales - a.sales)
            .map((item, idx) => ({ ...item, rank: idx + 1 }))
            .slice(0, 3);

          setLeaderboard(sorted);
      };

      fetchData();
  }, [orders]);

  const paidOrders = orders.filter(o => o.status === OrderStatus.PAID);
  const totalRevenue = paidOrders.reduce((acc, order) => acc + order.total, 0);

  const targetProgress = Math.min((totalRevenue / dailyTarget) * 100, 100);

  const lowStockItems = ingredients.filter(i => i.currentStock <= i.minStockAlert);

  const risingPrices = ingredients.filter(i => i.priceHistory && i.priceHistory.length > 1 && i.priceHistory[i.priceHistory.length-1].price > i.priceHistory[0].price).slice(0, 3);

  const weeklyData = useMemo(() => {
    const days = ['Dum', 'Lun', 'Mar', 'Mie', 'Joi', 'Vin', 'Sam'];
    const last7Days = Array.from({ length: 7 }, (_, i) => {
        const d = new Date();
        d.setDate(d.getDate() - (6 - i));
        return d;
    });

    return last7Days.map(date => {
        const dateStr = date.toLocaleDateString();
        const dayOrders = paidOrders.filter(o => new Date(o.timestamp).toLocaleDateString() === dateStr);
        const daySales = dayOrders.reduce((acc, o) => acc + o.total, 0);
        return {
            name: days[date.getDay()],
            sales: daySales > 0 ? daySales : Math.floor(Math.random() * 500) + 200 // Mock fallback
        };
    });
  }, [paidOrders]);

