                                <option>Frigider Carne</option><option>Frigider Legume</option><option>Congelator 1</option>
                            </select>
                            <div className="flex items-center gap-4 mt-2">
                                <input type="range" min="-20" max="20" className="flex-1" value={tempData.temp} onChange={e => setTempData({...tempData, temp: Number(e.target.value)})}/>
                                <span className={`text-2xl font-bold w-16 text-center ${tempData.temp > 5 ? 'text-red-600' : 'text-emerald-600'}`}>{tempData.temp}°</span>
