                                <div>
                                    <div className="font-bold">{task.task}</div>
                                    <div className="text-xs text-slate-500 uppercase">{task.area} • {task.frequency}</div>
                                </div>
                                {!task.completed && <button onClick={() => handleCompleteTask(task.id)} className="p-2 bg-slate-100 rounded-full hover:bg-emerald-200"><PenTool size={16}/></button>}
                                {task.completed && <CheckCircle className="text-emerald-500"/>}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Other tabs omitted for brevity, following same pattern */}
        </div>
    </div>
  );
};
