      days: [] as number[]
  });

  const refreshData = async () => {
    const [v, p] = await Promise.all([
        ApiService.getVouchers(),
        ApiService.getPromotions()
    ]);
    setVouchers(v);
    setPromos(p);
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleCreateVoucher = async () => {
    const code = prompt("Introdu cod voucher (ex: SUMMER20):");
    if (!code) return;
    const val = Number(prompt("Valoare procentuala (ex: 20):"));
    if (!val) return;

    const newVoucher: Voucher = {
        id: Date.now().toString(),
        code: code.toUpperCase(),
        type: 'percent',
        value: val,
        active: true,
        maxUses: 100,
        usedCount: 0,
        expiresAt: new Date(Date.now() + 86400000 * 30).toISOString().split('T')[0]
    };
    await ApiService.createVoucher(newVoucher);
    refreshData();
  };

