        ) : (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex-1 ag-theme-quartz">
                <AgGridReact rowData={entries} columnDefs={defs} pagination={true} paginationPageSize={20}/>
