                        <Server size={32}/>
                    </div>
                    <div>
                        <div className={`text-2xl font-bold uppercase ${status === 'online' ? 'text-emerald-600' : 'text-red-600'}`}>{status}</div>
                        <div className="text-sm text-slate-500">Latency: {latency}ms</div>
