// INVENTORY (Update production route)
app.post('/api/inventory/production', async (req, res) => {
    const { productId, quantity } = req.body;
    try {
        const product = await prisma.product.findUnique({ where: { id: productId }, include: { recipe: true } });

        if(product && product.recipe) {
            // Transaction: Deduct raw materials
            for(const rItem of product.recipe) {
                await prisma.ingredient.update({
                    where: { id: rItem.ingredientId },
                    data: { currentStock: { decrement: rItem.quantity * quantity } }
                });
            }
            // Optional: Increment finished good stock if you track it as an ingredient
            // For now, we just confirm the deduction of raw materials

            await prisma.auditLog.create({ 
                data: { 
                    action: 'PRODUCTION', 
                    user: 'Kitchen', 
                    details: `Produced ${quantity}x ${product.name}`, 
                    timestamp: Date.now() 
                } 
            });

            res.json({ success: true });
        } else {
            res.status(404).json({ error: "Recipe not found" });
        }
    } catch (e) {
        console.error(e);
        res.status(500).json({ error: "Production failed" });
    }
});

