}

datasource db {
  provider = "sqlite"
  url      = "file:./dev.db"
}

// --- CONFIGURATION ---
model SystemSettings {
  id        String   @id @default("default")
  data      String   // Stores JSON: restaurantName, cui, printers, vatRate, etc.
  updatedAt DateTime @updatedAt
}

model Table {
  id        Int      @id
  zone      String
  seats     Int
  occupied  Boolean  @default(false)
  reserved  Boolean  @default(false)
  shape     String   // round, square, rectangle
  x         Float?   // Percentage X coordinate for visual map
  y         Float?   // Percentage Y coordinate for visual map
}

// --- HR & STAFF ---
model User {
  id        String   @id @default(uuid())
  name      String
  pin       String
  role      String   // admin, manager, waiter, chef, bartender, driver
  active    Boolean  @default(true)
  tipPoints Float?   @default(0)
  skills    String?  // JSON array of skill IDs
  shifts    Shift[]
  logs      AuditLog[]
}

model Shift {
